  next_out_l = next_out_l + {1'b0, amplitude_l}; 
  next_out_r = next_out_r + {1'b0, amplitude_r}; 
  end 
  end 
  always @(posedge clk) begin 
  out_l <= next_out_l; 
  out_r <= next_out_r; 
  end 
 endmodule

