  7'b0111111: SSLED = 7'b1111101; 
  7'b1111101: SSLED = 7'b1111011; 
  7'b1111011: SSLED = 7'b1110111; 
  7'b1110111: SSLED = 7'b1101111; 
  7'b1101111: SSLED = 7'b1011111; 
  7'b1011111: SSLED = 7'b0111111; 
  default: SSLED = 7'b0111111; 
  endcase 
  end 
  end 
 endmodule

