module rtlpp_01391(clk, segment, anode, word);

   parameter SEG_UNITS = 4;
   parameter INVERT_ANODES = 1;
   parameter INVERT_SEGMENTS = 1;

   input clk;
   output [(SEG_UNITS - 1):0] anode;
   output [7:0] segment;
   input [(SEG_UNITS * 8 - 1):0] word;

   reg [15:0] cnt;
   reg [3:0] an_index;
   reg [7:0] SevenSeg;
   reg [(SEG_UNITS * 8 - 1):0] word_shifted;

   wire cntovf = &cnt;

   always @(posedge clk) 
       cnt <= cnt + 16'h1;

   always @(posedge cntovf)
       if (an_index == SEG_UNITS - 1)
           an_index <= 0;
       else
           an_index <= an_index + 1;

   always @(posedge clk)
       word_shifted <= word >> (an_index * 8);

   assign segment = INVERT_SEGMENTS ? ~word_shifted[7:0] : word_shifted[7:0];

   localparam [(SEG_UNITS - 1):0] anode_init = 1;

   assign anode = INVERT_ANODES ? ~(anode_init << an_index) : (anode_init << an_index);

endmodule

