  wire    SRAM_CE_N_wire /*synthesis keep */;
  wire    SRAM_WE_N_wire /*synthesis keep */;
  wire    SRAM_OE_N_wire /*synthesis keep */;
  wire    SRAM_UB_N_wire /*synthesis keep */;
  wire    SRAM_LB_N_wire /*synthesis keep */;


