  AND : {C_q, ACC_q} <= {1'b0, ACC_q & B_q}; 
  NOT : ACC_q <= ~ACC_q; 
  ADC : {C_q,ACC_q} <= ACC_q + C_q + B_q; 
  JAL : {B_q,ACC_q} <= {6'b0,PC_q} ; 
  LDB : B_q <= OR_q[7:0]; 
  LDBP: B_q <= OR_q[7:0]; 
  LDBI: B_q <= OR_q[7:0]; 
  endcase 
  end 
  always @ (posedge clk or negedge reset_b ) 
  if (!reset_b) 
  PC_q <= 10'h100; 
  else 
  if ( FSM_q == FETCH0 || FSM_q == FETCH1 ) 
  PC_q <= PC_q + 1; 
  else if ( FSM_q == EXEC ) 
  case (IR_q) 
  JAL : PC_q <= {B_q[1:0],ACC_q}; 
  JPC : PC_q <= (C_q)?OR_q:PC_q; 
  endcase 
 endmodule

