  parameter LDAP=5'b01001, STA=5'b11000, STAP=5'b01000; 
  parameter JPC=5'b11001, JPZ=5'b11010, JP=5'b11011, JSR=5'b11100; 
  parameter RTS=5'b11101, LXA=5'b11110; 
