  count <= 4'b0; 
  ok <= 1'b0; 
  ack <= 1'b1; 
  state <= STATE_FINISH; 
  end 
  STATE_FINISH: begin 
  ack <= 1'b0; 
  state <= STATE_IDLE; 
  end 
  endcase 
  end 
 end 
 always@(posedge clk_i) begin 
  if(ok && !write_i) begin 
  data = memory[addr]; 
  end 
 end 
 always@(posedge clk_i) begin 
  if(ok && write_i) begin 
  memory[addr] <= data_i; 
  end 
 end 
 endmodule

