module autovcoder_009099 (
    input [7:0] I0,
    input [7:0] I1,
    output O
);
  wire inst0_O;
  wire inst1_O;
  wire inst2_O;
  wire inst3_O;
  wire inst4_O;
  wire inst5_O;
  wire inst6_O;
  wire inst7_O;
  SB_LUT4 #(
      .LUT_INIT(16'h8282)
  ) inst0 (
      .I0(1'b1),
      .I1(I0[0]),
      .I2(I1[0]),
      .I3(1'b0),
      .O (inst0_O)
  );
  SB_LUT4 #(
      .LUT_INIT(16'h8282)
  ) inst1 (
      .I0(inst0_O),
      .I1(I0[1]),
      .I2(I1[1]),
      .I3(1'b0),
      .O (inst1_O)
  );
  SB_LUT4 #(
      .LUT_INIT(16'h8282)
  ) inst2 (
      .I0(inst1_O),
      .I1(I0[2]),
      .I2(I1[2]),
      .I3(1'b0),
      .O (inst2_O)
  );
  SB_LUT4 #(
      .LUT_INIT(16'h8282)
  ) inst3 (
      .I0(inst2_O),
      .I1(I0[3]),
      .I2(I1[3]),
      .I3(1'b0),
      .O (inst3_O)
  );
  SB_LUT4 #(
      .LUT_INIT(16'h8282)
  ) inst4 (
