module origen_133196(
    input [15:0] D,
    input [15:0] V,
    output equal,
    output greater,
    output [15:0] Q,
    output [15:0] R,
    output [3:0] final_output
);

    wire comp_equal, comp_greater;
    wire [15:0] div_quotient, div_remainder;

    // Instantiate 4-bit magnitude comparator
    magnitude_comparator comparator (
        .A(D[3:0]),
        .B(V[3:0]),
        .equal(comp_equal),
        .greater(comp_greater)
    );

    // Instantiate 16-bit unsigned division module
    unsigned_divider divider (
        .dividend(D),
        .divisor(V),
        .quotient(div_quotient),
        .remainder(div_remainder)
    );

    // Assign outputs
    assign equal = (D == V);
    assign greater = (D > V);
    assign Q = div_quotient;
    assign R = div_remainder;

    // Additional functional module for final output
    output_selector selector (
        .equal(equal),
        .greater(greater),
        .quotient(div_quotient),
        .final_output(final_output)
    );

endmodule

// 4-bit magnitude comparator
module magnitude_comparator(
    input [3:0] A,
    input [3:0] B,
    output equal,
    output greater
);

    assign equal = (A == B);
    assign greater = (A > B);

endmodule

// 16-bit unsigned division module
module unsigned_divider(
    input [15:0] dividend,
    input [15:0] divisor,
    output reg [15:0] quotient,
    output reg [15:0] remainder
);

    integer i;
    reg [31:0] temp_dividend;

    always @(*) begin
        temp_dividend = {16'b0, dividend};
        quotient = 16'b0;

        for (i = 0; i < 16; i = i + 1) begin
            temp_dividend = temp_dividend << 1;
            if (temp_dividend[31:16] >= divisor) begin
                temp_dividend[31:16] = temp_dividend[31:16] - divisor;
                quotient = (quotient << 1) | 1'b1;
            end else begin
                quotient = quotient << 1;
            end
        end

        remainder = temp_dividend[31:16];
    end

endmodule

// Additional functional module for final output
module output_selector(
    input equal,
    input greater,
    input [15:0] quotient,
    output reg [3:0] final_output
);

    always @(*) begin
        if (greater)
            final_output = quotient[15:12];
        else
            final_output = quotient[3:0];
    end

endmodule

