                end
                4'b1010: begin
                    mux_A_sel = 2'b10;
                    mux_B_sel = 2'b00;
                end
                4'b1011: begin
                    mux_A_sel = 2'b11;
                    mux_B_sel = 2'b01;
                end
                4'b1100: begin
                    mux_A_sel = 2'b00;
                    mux_B_sel = 2'b11;
                end
                4'b1101: begin
                    mux_A_sel = 2'b01;
                    mux_B_sel = 2'b10;
                end
                4'b1110: begin
                    mux_A_sel = 2'b10;
                    mux_B_sel = 2'b01;
                end
                4'b1111: begin
                    mux_A_sel = 2'b11;
                    mux_B_sel = 2'b00;
                end
            endcase

            case (mux_A_sel)
                2'b00: bus_A = data_A;
                2'b01: bus_A = data_B;
                2'b10: bus_A = {22'b0, PC_1};
                2'b11: bus_A = data_D_prime;
            endcase

            case (mux_B_sel)
                2'b00: bus_B = data_A;
                2'b01: bus_B = data_B;
                2'b10: bus_B = const_unit;
                2'b11: bus_B = {22'b0, PC_1};
            endcase
        end
    end

endmodule

