module autovcoder_095558 #(
    parameter [63:0] INIT_A           = 64'h0,
    parameter [63:0] INIT_B           = 64'h0,
    parameter [63:0] INIT_C           = 64'h0,
    parameter [63:0] INIT_D           = 64'h0,
    parameter [63:0] INIT_E           = 64'h0,
    parameter [63:0] INIT_F           = 64'h0,
    parameter [63:0] INIT_G           = 64'h0,
    parameter [63:0] INIT_H           = 64'h0,
    parameter [ 0:0] IS_WCLK_INVERTED = 1'b0
) (
    // Write clock
    input  wire       WCLK,
    // Write enable
    input  wire       WE,
    // Port A
    input  wire [5:0] ADDRA,
    input  wire       DIA,
    output wire       DOA,
    // Port B
    input  wire [5:0] ADDRB,
    input  wire       DIB,
    output wire       DOB,
    // Port C
    input  wire [5:0] ADDRC,
    input  wire       DIC,
    output wire       DOC,
    // Port D
    input  wire [5:0] ADDRD,
    input  wire       DID,
    output wire       DOD,
    // Port E
    input  wire [5:0] ADDRE,
    input  wire       DIE,
    output wire       DOE,
    // Port F
    input  wire [5:0] ADDRF,
    input  wire       DIF,
    output wire       DOF,
    // Port G
    input  wire [5:0] ADDRG,
    input  wire       DIG,
    output wire       DOG,
    // Port H
    input  wire [5:0] ADDRH,
    input  wire       DIH,
    output wire       DOH
);
  // 64 x 8-bit Select RAM
  reg [63:0] _r_mem_a;
  reg [63:0] _r_mem_b;
  reg [63:0] _r_mem_c;
  reg [63:0] _r_mem_d;
  reg [63:0] _r_mem_e;
  reg [63:0] _r_mem_f;
  reg [63:0] _r_mem_g;
  reg [63:0] _r_mem_h;

  // Power-up value
  initial begin : INIT_STATE
    _r_mem_a = INIT_A;
    _r_mem_b = INIT_B;
    _r_mem_c = INIT_C;
    _r_mem_d = INIT_D;
    _r_mem_e = INIT_E;
    _r_mem_f = INIT_F;
    _r_mem_g = INIT_G;
    _r_mem_h = INIT_H;
  end

  // Synchronous memory write
  generate
    if (IS_WCLK_INVERTED) begin : GEN_WCLK_NEG
      always @(negedge WCLK) begin : MEM_WRITE

        if (WE) begin
          _r_mem_a[ADDRH] <= DIA;
          _r_mem_b[ADDRH] <= DIB;
          _r_mem_c[ADDRH] <= DIC;
          _r_mem_d[ADDRH] <= DID;
          _r_mem_e[ADDRH] <= DIE;
          _r_mem_f[ADDRH] <= DIF;
          _r_mem_g[ADDRH] <= DIG;
          _r_mem_h[ADDRH] <= DIH;
        end
      end
    end else begin : GEN_WCLK_POS
      always @(posedge WCLK) begin : MEM_WRITE

        if (WE) begin
          _r_mem_a[ADDRH] <= DIA;
          _r_mem_b[ADDRH] <= DIB;
          _r_mem_c[ADDRH] <= DIC;
          _r_mem_d[ADDRH] <= DID;
          _r_mem_e[ADDRH] <= DIE;
          _r_mem_f[ADDRH] <= DIF;
          _r_mem_g[ADDRH] <= DIG;
          _r_mem_h[ADDRH] <= DIH;
        end
      end
    end
  endgenerate

  // Asynchronous memory read
  assign DOA = _r_mem_a[ADDRA];
  assign DOB = _r_mem_b[ADDRB];
  assign DOC = _r_mem_c[ADDRC];
  assign DOD = _r_mem_d[ADDRD];
  assign DOE = _r_mem_e[ADDRE];
  assign DOF = _r_mem_f[ADDRF];
  assign DOG = _r_mem_g[ADDRG];
  assign DOH = _r_mem_h[ADDRH];

endmodule

