  S_START: begin 
  if (w_phase_shift) begin 
  r_state <= S_BIT0; 
  r_tx <= r_data[0]; 
  end 
  end 
  S_BIT0: begin 
  if (w_phase_shift) begin 
  r_state <= S_BIT1; 
  r_tx <= r_data[1]; 
  end 
  end 
