    assign pre_xval = xv[NSTAGES] + { {OW{1'b0}}, xv[NSTAGES][WW-OW], {WW-OW-1{!xv[NSTAGES][WW-OW]}} };
    assign pre_yval = yv[NSTAGES] + { {OW{1'b0}}, yv[NSTAGES][WW-OW], {WW-OW-1{!yv[NSTAGES][WW-OW]}} };

