module rtlpp_01087(
    input clk, 
    input rst, 
    input rx,  
    output tx, 
    input transmit,         
    input [7:0] tx_byte,    
    output received,        
    output [7:0] rx_byte,   
    output is_receiving,    
    output is_transmitting, 
    output recv_error       
    );

parameter CLOCK_DIVIDE = 651; 

parameter RX_IDLE = 3'd0;
parameter RX_CHECK_START = 3'd1;
parameter RX_READ_BITS = 3'd2;
parameter RX_CHECK_STOP = 3'd3;
parameter RX_DELAY_RESTART = 3'd4;
parameter RX_ERROR = 3'd5;
parameter RX_RECEIVED = 3'd6;

parameter TX_IDLE = 2'd0;
parameter TX_SENDING = 2'd1;
parameter TX_DELAY_RESTART = 2'd2;

reg [10:0] rx_clk_divider = CLOCK_DIVIDE;
reg [10:0] tx_clk_divider = CLOCK_DIVIDE;

reg rx_ff;
reg [2:0] recv_state = RX_IDLE;
reg [5:0] rx_countdown;
reg [3:0] rx_bits_remaining;
reg [7:0] rx_data;

reg tx_out = 1;
reg [1:0] tx_state = TX_IDLE;
reg [5:0] tx_countdown;
reg [3:0] tx_bits_remaining;
reg [7:0] tx_data;

assign received = (recv_state == RX_RECEIVED);
assign recv_error = (recv_state == RX_ERROR);
assign is_receiving = (recv_state != RX_IDLE);
assign rx_byte = rx_data;

assign tx = tx_out;
assign is_transmitting = (tx_state != TX_IDLE);

always @(posedge clk or posedge rst) begin
  if (rst) begin
    recv_state <= RX_IDLE;
    tx_state <= TX_IDLE;
  end
  else begin
    // Receive block
    rx_ff <= rx;
    rx_clk_divider <= rx_clk_divider - 1;
    if (!rx_clk_divider) begin
      rx_clk_divider <= CLOCK_DIVIDE;
      rx_countdown <= rx_countdown - 1;
    end

    // Transmit block
    tx_clk_divider <= tx_clk_divider - 1;
    if (!tx_clk_divider) begin
      tx_clk_divider <= CLOCK_DIVIDE;
      tx_countdown <= tx_countdown - 1;
    end

    // Receiver state machine
    case (recv_state)
      RX_IDLE: begin
        if (!rx_ff) begin
          rx_clk_divider <= CLOCK_DIVIDE;
          rx_countdown <= 6'd8;
          recv_state <= RX_CHECK_START;
        end
      end

      RX_CHECK_START: begin
        if (!rx_countdown) begin
          if (!rx_ff) begin
            rx_countdown <= 6'd16;
            rx_bits_remaining <= 4'd8;
            recv_state <= RX_READ_BITS;
          end else begin
            recv_state <= RX_ERROR;
          end
        end
      end

      RX_READ_BITS: begin
        if (!rx_countdown) begin
          rx_data <= {rx_ff, rx_data[7:1]};
          rx_countdown <= 6'd16;
          rx_bits_remaining <= rx_bits_remaining - 1;
          recv_state <= (rx_bits_remaining ? RX_READ_BITS : RX_CHECK_STOP);
        end
      end

      RX_CHECK_STOP: begin
        if (!rx_countdown) begin
          recv_state <= (rx_ff ? RX_RECEIVED : RX_ERROR);
        end
      end

      RX_DELAY_RESTART: begin
        recv_state <= (rx_countdown ? RX_DELAY_RESTART : RX_IDLE);
      end

      RX_ERROR: begin
        rx_countdown <= 6'd32;
        recv_state <= RX_DELAY_RESTART;
      end

      RX_RECEIVED: begin
        recv_state <= RX_IDLE;
      end

      default: recv_state <= RX_IDLE;
    endcase

    // Transmitter state machine
    case (tx_state)
      TX_IDLE: begin
        if (transmit) begin
          tx_data <= tx_byte;
          tx_clk_divider <= CLOCK_DIVIDE;
          tx_countdown <= 6'd16;
          tx_out <= 0;
          tx_bits_remaining <= 4'd8;
          tx_state <= TX_SENDING;
        end
      end

      TX_SENDING: begin
        if (!tx_countdown) begin
          if (tx_bits_remaining) begin
            tx_bits_remaining <= tx_bits_remaining - 1;
            tx_out <= tx_data[0];
            tx_data <= {1'b0, tx_data[7:1]};
            tx_countdown <= 6'd16;
          end else begin
            tx_out <= 1;
            tx_countdown <= 6'd32;
            tx_state <= TX_DELAY_RESTART;
          end
        end
      end

      TX_DELAY_RESTART: begin
        tx_state <= (tx_countdown ? TX_DELAY_RESTART : TX_IDLE);
      end

      default: tx_state <= TX_IDLE;
    endcase
  end
end

endmodule

