module origen_146855 (
    input wire spi_clk,
    input wire nreset,
    input wire spi_write,
    input wire [5:0] spi_addr,
    input wire [7:0] spi_wdata,
    input wire [31:0] packet_in [0:7],

    output reg config_write,
    output reg status_write,
    output reg user_write,
    output reg wait_out,
    output reg write_in,
    output reg [1:0] datamode_in,
    output reg [4:0] ctrlmode_in,
    output reg [31:0] dstaddr_in,
    output reg [31:0] srcaddr_in,
    output reg [31:0] data_in,
    output reg spi_en,
    output reg irq_en,
    output reg cpol,
    output reg cpha,
    output reg lsbfirst,
    output reg valid,
    output reg [7:0] user_regs [0:7],
    output reg [7:0] spi_status,
    output reg [63:0] core_data,
    output reg [63:0] core_regs,
    output reg [255:0] spi_regs,
    output reg [7:0] spi_rdata
);

    // Internal registers
    reg [7:0] config_reg;
    reg [7:0] status_reg;
    integer i;

    always @(posedge spi_clk or negedge nreset) begin
        if (!nreset) begin
            config_write <= 0;
            status_write <= 0;
            user_write <= 0;
            wait_out <= 0;
            write_in <= 0;
            datamode_in <= 2'b00;
            ctrlmode_in <= 5'b00000;
            dstaddr_in <= 32'h0;
            srcaddr_in <= 32'h0;
            data_in <= 32'h0;
            spi_en <= 0;
            irq_en <= 0;
            cpol <= 0;
            cpha <= 0;
            lsbfirst <= 0;
            valid <= 0;
            spi_status <= 8'h0;
            core_data <= 64'h0;
            core_regs <= 64'h0;
            spi_regs <= 256'h0;
            spi_rdata <= 8'h0;
            config_reg <= 8'h0;
            status_reg <= 8'h0;
            for (i = 0; i < 8; i = i + 1) begin
                user_regs[i] <= 8'h0;
            end
        end else if (spi_write) begin
            case (spi_addr)
                6'h00: begin // Config register
                    config_reg <= spi_wdata;
                    config_write <= 1;
                    spi_en <= spi_wdata[0];
                    irq_en <= spi_wdata[1];
                    cpol <= spi_wdata[2];
                    cpha <= spi_wdata[3];
                    lsbfirst <= spi_wdata[4];
                end
                6'h01: begin // Status register
                    status_reg <= spi_wdata;
                    status_write <= 1;
                    spi_status <= spi_wdata;
                end
                6'h02: begin // User registers
                    user_regs[0] <= spi_wdata;
                    user_write <= 1;
                    valid <= 1;
                end
                6'h03: user_regs[1] <= spi_wdata;
                6'h04: user_regs[2] <= spi_wdata;
                6'h05: user_regs[3] <= spi_wdata;
                6'h06: user_regs[4] <= spi_wdata;
                6'h07: user_regs[5] <= spi_wdata;
                6'h08: user_regs[6] <= spi_wdata;
                6'h09: user_regs[7] <= spi_wdata;
                6'h0A: begin
                    datamode_in <= spi_wdata[1:0];
                    ctrlmode_in <= spi_wdata[6:2];
                end
                6'h0B: dstaddr_in[31:24] <= spi_wdata;
                6'h0C: dstaddr_in[23:16] <= spi_wdata;
                6'h0D: dstaddr_in[15:8] <= spi_wdata;
                6'h0E: dstaddr_in[7:0] <= spi_wdata;
                6'h0F: srcaddr_in[31:24] <= spi_wdata;
                6'h10: srcaddr_in[23:16] <= spi_wdata;
                6'h11: srcaddr_in[15:8] <= spi_wdata;
                6'h12: srcaddr_in[7:0] <= spi_wdata;
                6'h13: data_in[31:24] <= spi_wdata;
                6'h14: data_in[23:16] <= spi_wdata;
                6'h15: data_in[15:8] <= spi_wdata;
                6'h16: data_in[7:0] <= spi_wdata;
                default: begin
                    // Do nothing for undefined addresses
                end
            endcase
        end else begin
            config_write <= 0;
            status_write <= 0;
            user_write <= 0;
        end
    end

    // Assign core_data and core_regs
    always @(posedge spi_clk) begin
        core_data <= {packet_in[1], packet_in[0]};
        core_regs <= {user_regs[1], user_regs[0], config_reg, status_reg};
    end

    // Assign spi_regs
    always @(posedge spi_clk) begin
        spi_regs <= {user_regs[7], user_regs[6], user_regs[5], user_regs[4],
                     user_regs[3], user_regs[2], user_regs[1], user_regs[0],
                     config_reg, status_reg, 16'h0000, 16'h0000, 16'h0000, 16'h0000};
    end

    // Assign spi_rdata (for read operations)
    always @(posedge spi_clk) begin
        case (spi_addr)
            6'h00: spi_rdata <= config_reg;
            6'h01: spi_rdata <= status_reg;
            6'h02: spi_rdata <= user_regs[0];
            6'h03: spi_rdata <= user_regs[1];
            6'h04: spi_rdata <= user_regs[2];
            6'h05: spi_rdata <= user_regs[3];
            6'h06: spi_rdata <= user_regs[4];
            6'h07: spi_rdata <= user_regs[5];
            6'h08: spi_rdata <= user_regs[6];
            6'h09: spi_rdata <= user_regs[7];
            default: spi_rdata <= 8'h00;
        endcase
    end

endmodule

