module origen_169004(
    input [5:0] Opcode,
    input [5:0] Funct,
    output reg [3:0] ALUop,
    output reg RegDst,
    output reg RegWrite,
    output reg MemRead,
    output reg MemWrite,
    output reg ALUSrc,
    output reg MemtoReg,
    output reg Branch,
    output reg NotEqualBranch,
    output reg Jump
);

    always @(*) begin
        case (Opcode)
            6'b000000: begin // R-type instructions
                case (Funct)
                    6'b100000: begin // add
                        ALUop = 4'b0010;
                        RegDst = 1'b1;
                        RegWrite = 1'b1;
                        MemRead = 1'b0;
                        MemWrite = 1'b0;
                        ALUSrc = 1'b0;
                        MemtoReg = 1'b0;
                        Branch = 1'b0;
                        NotEqualBranch = 1'b0;
                        Jump = 1'b0;
                    end
                    6'b100010: begin // sub
                        ALUop = 4'b0110;
                        RegDst = 1'b1;
                        RegWrite = 1'b1;
                        MemRead = 1'b0;
                        MemWrite = 1'b0;
                        ALUSrc = 1'b0;
                        MemtoReg = 1'b0;
                        Branch = 1'b0;
                        NotEqualBranch = 1'b0;
                        Jump = 1'b0;
                    end
                    6'b100100: begin // and
                        ALUop = 4'b0000;
                        RegDst = 1'b1;
                        RegWrite = 1'b1;
                        MemRead = 1'b0;
                        MemWrite = 1'b0;
                        ALUSrc = 1'b0;
                        MemtoReg = 1'b0;
                        Branch = 1'b0;
                        NotEqualBranch = 1'b0;
                        Jump = 1'b0;
