module rtlpp_01165(
           iSTART,
           iRST_n,
           iCLK_50,
           PS2_CLK,
           PS2_DAT,
           oLEFBUT,
           oRIGBUT,
           oMIDBUT,
           oX,
           oY,
           oX_MOV1,
           oX_MOV2,
           oY_MOV1,
           oY_MOV2
           );

input iSTART;
input iRST_n;
input iCLK_50;

inout PS2_CLK;
inout PS2_DAT;

output oLEFBUT;
output oRIGBUT;
output oMIDBUT;
output [7:0] oX;
output [7:0] oY;
output [6:0] oX_MOV1;
output [6:0] oX_MOV2;
output [6:0] oY_MOV1;
output [6:0] oY_MOV2;

parameter enable_byte = 9'b011110100;

reg [1:0] cur_state, nex_state;
reg ce, de;
reg [3:0] byte_cnt, delay;
reg [5:0] ct;
reg [7:0] x_latch, y_latch, cnt;
reg [8:0] clk_div;
reg [9:0] dout_reg;
reg [32:0] shift_reg;
reg leflatch, riglatch, midlatch;
reg ps2_clk_in, ps2_clk_syn1, ps2_dat_in, ps2_dat_syn1;

wire clk, ps2_dat_syn0, ps2_clk_syn0, ps2_dat_out, ps2_clk_out, flag;

parameter listen   = 2'b00,
          pullclk  = 2'b01,
          pulldat  = 2'b10,
          trans    = 2'b11;

always @(posedge iCLK_50)
    clk_div <= clk_div + 1;

assign clk = clk_div[8];
assign PS2_CLK = ce ? ps2_clk_out : 1'bz;
assign PS2_DAT = de ? ps2_dat_out : 1'bz;
assign ps2_clk_out = 1'b0;
assign ps2_dat_out = dout_reg[0];
assign ps2_clk_syn0 = ce ? 1'b1 : PS2_CLK;
assign ps2_dat_syn0 = de ? 1'b1 : PS2_DAT;

assign oLEFBUT = leflatch;
assign oRIGBUT = riglatch;
assign oMIDBUT = midlatch;
assign oX = x_latch;
assign oY = y_latch;

always @(posedge clk) begin
    ps2_clk_syn1 <= ps2_clk_syn0;
    ps2_clk_in <= ps2_clk_syn1;
    ps2_dat_syn1 <= ps2_dat_syn0;
    ps2_dat_in <= ps2_dat_syn1;
end

always @(*) begin
    case (cur_state)
        listen: begin
            if ((!iSTART) && (cnt == 8'b11111111))
                nex_state = pullclk;
            else
                nex_state = listen;
            ce = 1'b0;
            de = 1'b0;
        end
        pullclk: begin
            if (delay == 4'b1100)
                nex_state = pulldat;
            else
                nex_state = pullclk;
            ce = 1'b1;
            de = 1'b0;
        end
        pulldat: begin
            nex_state = trans;
            ce = 1'b1;
            de = 1'b1;
        end
        trans: begin
            if (byte_cnt == 4'b1010)
                nex_state = listen;
            else
                nex_state = trans;
            ce = 1'b0;
            de = 1'b1;
        end
        default: nex_state = listen;
    endcase
end

always @(posedge clk) begin
    if ({ps2_clk_in, ps2_dat_in} == 2'b11)
        cnt <= cnt + 1;
    else
        cnt <= 8'd0;
end

assign flag = (cnt == 8'hff) ? 1 : 0;

always @(posedge ps2_clk_in or posedge flag) begin
    if (flag)
        ct <= 6'b000000;
    else
        ct <= ct + 1;
end

always @(posedge clk or negedge iRST_n) begin
    if (!iRST_n) begin
        leflatch <= 1'b0;
        riglatch <= 1'b0;
        midlatch <= 1'b0;
        x_latch <= 8'd0;
        y_latch <= 8'd0;
    end else if (cnt == 8'b00011110 && (ct[5] == 1'b1 || ct[4] == 1'b1)) begin
        leflatch <= shift_reg[1];
        riglatch <= shift_reg[2];
        midlatch <= shift_reg[3];
        x_latch <= x_latch + shift_reg[19:12];
        y_latch <= y_latch + shift_reg[30:23];
    end
end

always @(posedge clk) begin
    if (cur_state == pullclk)
        delay <= delay + 1;
    else
        delay <= 4'b0000;
end

always @(negedge ps2_clk_in) begin
    if (cur_state == trans)
        dout_reg <= {1'b0, dout_reg[9:1]};
    else
        dout_reg <= {enable_byte, 1'b0};
end

always @(negedge ps2_clk_in) begin
    if (cur_state == trans)
        byte_cnt <= byte_cnt + 1;
    else
        byte_cnt <= 4'b0000;
end

always @(negedge ps2_clk_in) begin
    if (cur_state == listen)
        shift_reg <= {ps2_dat_in, shift_reg[32:1]};
end

always @(posedge clk or negedge iRST_n) begin
    if (!iRST_n)
        cur_state <= listen;
    else
        cur_state <= nex_state;
end

// Internal logic of the SEG7_LUT module for oX_MOV1, oX_MOV2, oY_MOV1, oY_MOV2
function [6:0] seg7_lut(input [3:0] iDIG);
    case (iDIG)
        4'd0: seg7_lut = 7'b1000000;
        4'd1: seg7_lut = 7'b1111001;
        4'd2: seg7_lut = 7'b0100100;
        4'd3: seg7_lut = 7'b0110000;
        4'd4: seg7_lut = 7'b0011001;
        4'd5: seg7_lut = 7'b0010010;
        4'd6: seg7_lut = 7'b0000010;
        4'd7: seg7_lut = 7'b1111000;
        4'd8: seg7_lut = 7'b0000000;
        4'd9: seg7_lut = 7'b0010000;
        4'd10: seg7_lut = 7'b0001000;
        4'd11: seg7_lut = 7'b0000011;
        4'd12: seg7_lut = 7'b1000110;
        4'd13: seg7_lut = 7'b0100001;
        4'd14: seg7_lut = 7'b0000110;
        4'd15: seg7_lut = 7'b0001110;
        default: seg7_lut = 7'b1111111;
    endcase
endfunction

assign oX_MOV1 = seg7_lut(x_latch[3:0]);
assign oX_MOV2 = seg7_lut(x_latch[7:4]);
assign oY_MOV1 = seg7_lut(y_latch[3:0]);
assign oY_MOV2 = seg7_lut(y_latch[7:4]);

endmodule

