module autovcoder_087573 (
    clk,
    ra,
    re,
    ore,
    dout,
    wa,
    we,
    di,
    byp_sel,
    dbyp,
    pwrbus_ram_pd
);
  parameter FORCE_CONTENTION_ASSERTION_RESET_ACTIVE = 1'b0;
  // port list
  input clk;
  input [4:0] ra;
  input re;
  input ore;
  output [31:0] dout;
  input [4:0] wa;
  input we;
  input [31:0] di;
  input byp_sel;
  input [31:0] dbyp;
  input [31:0] pwrbus_ram_pd;
  //reg and wire list
  reg [4:0] ra_d;
  wire [31:0] dout;
  reg [31:0] M[19:0];
  always @(posedge clk) begin
    if (we) M[wa] <= di;
  end
  always @(posedge clk) begin
    if (re) ra_d <= ra;
  end
  wire [31:0] dout_ram = M[ra_d];
  wire [31:0] fbypass_dout_ram = (byp_sel ? dbyp : dout_ram);
  reg  [31:0] dout_r;
  always @(posedge clk) begin
    if (ore) dout_r <= fbypass_dout_ram;
  end
  assign dout = dout_r;
endmodule

