                    request_out <= 1'b1;
                    BWDAUX1_out <= 1'b0;
                end
                6'b000110: begin
                    enable_0 <= !busy_out ? 1'b1 : 1'b0;
                    enable_all <= 1'b0;
                    sel <= 6'b100000;
                    request_out <= 1'b1;
                    BWDAUX1_out <= 1'b1;
                end
                default: begin
                    enable_0 <= 1'bx;
                    enable_all <= 1'bx;
                    sel <= 6'b000001;
                    request_out <= 1'b0;
                    BWDAUX1_out <= 1'b0;
                end
            endcase
        end

    always @(FLIT_in or sel or flit[0] or flit[1] or flit[2] or flit[3] or flit[4])
        begin: mux
            case (sel)
                6'b000001: mux_out <= FLIT_in;
                6'b000010: mux_out <= flit[0];
                6'b000100: mux_out <= flit[1];
                6'b001000: mux_out <= flit[2];
                6'b010000: mux_out <= flit[3];
                6'b100000: mux_out <= flit[4];
                default: mux_out <= flit[0];
            endcase
        end

    always @(posedge clk or posedge rst)
        begin: flip_flop
            if (rst)
            begin
                flit_out <= 0;
                for (loop = 0; loop < 5; loop = loop + 1)
                    flit[loop] <= 0;
            end
            else
            begin
                if (enable_0 == 1'b1)
                    flit_out <= mux_out;
                if (enable_all == 1'b1)
                begin
                    flit[0] <= FLIT_in;
                    for (loop = 1; loop < 5; loop = loop + 1)
                        flit[loop] <= flit[loop - 1];
                end
            end
        end

endmodule

