reg [3:0] dataCounter;
reg [7:0] shiftRegRX;

reg [10:0] clok2048MbodCounterTX;
reg [3:0] dataCounterTX;
reg [7:0] shiftRegTX;

always @(posedge clk) begin
    // Reception
    if (PinRX == 1'b0) begin
        clok2048MbodCounterRX <= 11'd35;
        dataCounter <= 4'd12;
    end else if (clok2048MbodCounterRX != 0) begin
        clok2048MbodCounterRX <= clok2048MbodCounterRX - 1;
        if (clok2048MbodCounterRX == 1) begin
            shiftRegRX <= {shiftRegRX[6:0], PinRX};
            dataCounter <= dataCounter - 1;
