                dataIN <= shiftRegRX;
                flagOUT_DataResive <= 1'b1;
            end
        end
    end else begin
        flagOUT_DataResive <= 1'b0;
    end

    // Transmission
    if (flagIN_DataRedy == 1'b1) begin
        clok2048MbodCounterTX <= 11'd35;
        dataCounterTX <= 4'd10;
        shiftRegTX <= dataOUT;
    end else if (clok2048MbodCounterTX != 0) begin
        clok2048MbodCounterTX <= clok2048MbodCounterTX - 1;
        if (clok2048MbodCounterTX == 1) begin
            PinTX <= shiftRegTX[0];
            shiftRegTX <= {1'b1, shiftRegTX[7:1]};
            dataCounterTX <= dataCounterTX - 1;
        end
    end else begin
        PinTX <= 1'b1;
    end
end

