module origen_053283 #(
    parameter dataWidth = 16
) (
    input wire clk,
    input wire reset,
    input wire cen,
    input wire signed [dataWidth-1:0] data_in,
    output wire done,
    output reg signed [dataWidth-1:0] data_out_2
);

    reg signed [dataWidth-1:0] data_out, data_out_1;
    reg cen_1, cen_2, cen_3;

    wire signed [dataWidth-1:0] one_pos, one_neg;
    assign one_pos = {1'b0, {(dataWidth-1){1'b1}}};  // 1 in fixed-point
    assign one_neg = {1'b1, {(dataWidth-1){1'b0}}};  // -1 in fixed-point

    // Stage 1: Hard Tanh Computation
    always @(*) begin
        if (cen) begin
            if (data_in < one_neg)
                data_out = one_neg;
            else if (data_in > one_pos)
                data_out = one_pos;
            else
                data_out = data_in;
        end else begin
            data_out = {dataWidth{1'bz}};
        end
    end

    // Pipeline stages and clock enable propagation
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out_1 <= 0;
            data_out_2 <= 0;
            cen_1 <= 0;
            cen_2 <= 0;
            cen_3 <= 0;
        end else begin
            // Stage 2
            data_out_1 <= data_out;
            cen_1 <= cen;

            // Stage 3
            data_out_2 <= data_out_1;
            cen_2 <= cen_1;

            // Final stage for done signal
            cen_3 <= cen_2;
        end
    end

    // Done signal
    assign done = cen_3;

endmodule

files.origen_119730.v:
module origen_119730 (
    input  logic        clk_i,
    input  logic        rst_n_i,
    input  logic        enb_i,
    input  logic        restart_flag_i,
    input  logic        pre_sum_flag_i,
    input  logic        output_flag_i,
    input  logic        busy_i,
    input  logic [7:0]  dta_i,
    input  logic [7:0]  dtb_i,
    output logic [7:0]  index_o,
    output logic [31:0] dt_o
);

    logic [7:0]  diff;
    logic [7:0]  abs_diff;
    logic [7:0]  latched_abs_diff;
    logic [31:0] sum_r;

    // Calculate difference and absolute value
    assign diff = dta_i - dtb_i;
    assign abs_diff = (diff[7]) ? (~diff + 1'b1) : diff;

    // Latch absolute difference
    always_ff @(posedge clk_i or negedge rst_n_i) begin
        if (~rst_n_i) begin
            latched_abs_diff <= 8'b0;
        end else if (pre_sum_flag_i) begin
            latched_abs_diff <= abs_diff;
        end
    end

    // Accumulate SAD and increment index
    always_ff @(posedge clk_i or negedge rst_n_i) begin
        if (~rst_n_i) begin
            sum_r   <= 32'b0;
            index_o <= 8'b0;
        end else if (restart_flag_i) begin
            sum_r   <= 32'b0;
            index_o <= 8'b0;
        end else if (busy_i) begin
            sum_r   <= sum_r + latched_abs_diff;
            index_o <= index_o + 1'b1;
        end
    end

    // Output final result and handle reset
    always_ff @(posedge clk_i or negedge rst_n_i) begin
        if (~rst_n_i) begin
            dt_o <= 32'b0;
        end else if (output_flag_i) begin
            dt_o <= sum_r;
        end
    end

endmodule

