module origen_000129(
    input wire clock,
    input wire k_tr,
    output reg [7:0] key_code
);

    reg [2:0] st;
    reg [5:0] step;
    reg [7:0] TT;
    reg [15:0] tmp;
    reg [15:0] tmpa;

    parameter step_r = 42;

    always @(posedge clock) begin
        if (k_tr) begin
            st <= 0;
            step <= 0;
            tmp <= 0;
        end else begin
            case (st)
                0: st <= 1;
