    end

    always @(*) begin
        case (TT[3:0])
            4'h1: key_code = (tmp < tmpa) ? 8'h2B : 8'hF0;
            4'h2: key_code = (tmp < tmpa) ? 8'h34 : 8'hF0;
            4'h3: key_code = (tmp < tmpa) ? 8'h33 : 8'hF0;
